    seen = set()

    for clause in clauses:
        fams = detect_families(clause, row[\"station\"], row[\"product_id\"])
        if not fams:
            key = (clause, UNKNOWN)
            if key not in seen:
                seen.add(key)
                normalized.append(
                    {
                        \"span_text\": clause,
                        \"pred_code\": UNKNOWN,
                        \"pred_label\": \"\",
                        \"confidence\": 0.14,
                        \"rationale\": f\"No reliable family keyword found for span='{clause}' at station={row['station']} test_item={row['test_item']}\",
                    }
                )
            continue

        top_fams = []
        top_score = fams[0][1]
        for fam, score in fams:
            if score >= top_score - 0.06:
                top_fams.append((fam, score))
        for fam, score in top_fams[:2]:
            code, label, conf, rationale = choose_candidate(row, clause, fam, score)
            key = (clause, code)
            if key in seen:
                continue
            seen.add(key)
            normalized.append(
                {
                    \"span_text\": clause,
                    \"pred_code\": code,
                    \"pred_label\": label,
                    \"confidence\": conf,
                    \"rationale\": rationale,
                }
            )

    if not normalized:
        normalized.append(
