        for fam, score in top_fams[:2]:
            code, label, conf, rationale = choose_candidate(row, clause, fam, score)
            key = (clause, code)
            if key in seen:
                continue
            seen.add(key)
            normalized.append(
                {
                    \"span_text\": clause,
                    \"pred_code\": code,
                    \"pred_label\": label,
                    \"confidence\": conf,
                    \"rationale\": rationale,
                }
            )

    if not normalized:
        normalized.append(
            {
                \"span_text\": raw,
                \"pred_code\": UNKNOWN,
                \"pred_label\": \"\",
                \"confidence\": 0.14,
                \"rationale\": f\"Fallback unknown for raw_reason_text='{raw}'\",
            }
        )

    for idx, seg in enumerate(normalized, start=1):
        seg[\"segment_id\"] = f\"{row['record_id']}-S{idx}\"

    return {
        \"record_id\": row[\"record_id\"],
        \"product_id\": row[\"product_id\"],
        \"station\": row[\"station\"],
        \"engineer_id\": row[\"engineer_id\"],
        \"raw_reason_text\": raw,
        \"normalized\": normalized,
    }


def main() -> None:
    records = []
    with open(f\"{DATA_DIR}/test_center_logs.csv\", \"r\", encoding=\"utf-8\") as f:
        for row in csv.DictReader(f):
            records.append(normalize_record(row))
    with open(OUT_JSON, \"w\", encoding=\"utf-8\") as f:
        json.dump({\"records\": records}, f, ensure_ascii=False, indent=2)


if __name__ == \"__main__\":
    main()
